class Solution:
    def removeBoxes(self, boxes: List[int]) -> int:
        from functools import lru_cache
        @lru_cache(None)
        def dp(l, r, k):
            if l > r: return 0
            while r > l and boxes[r] == boxes[r-1]:
                r -= 1
                k += 1
            ans = dp(l, r-1, 0) + (k+1)*(k+1)
            for p in range(l, r):
                if boxes[p] == boxes[r]:
                    ans = max(ans, dp(l, p, k+1) + dp(p+1, r-1, 0))
            return ans
        return dp(0, len(boxes)-1, 0)

